"""Minimal runtime shim for CPython's private _typing accelerator.

This file intentionally serves only the surface typing.py imports from the C
accelerator. typing.py keeps the higher-level generic/Protocol machinery in
Python; this shim provides the bootstrap classes and sentinels it expects.
"""

from __future__ import annotations

import types as _types


def _idfunc(x):
    return x


class _NoDefaultType:
    __slots__ = ()
    __module__ = "typing"

    def __repr__(self):
        return "typing.NoDefault"


NoDefault = _NoDefaultType()


class _TypeAliasTypeMeta(type):
    __module__ = "typing"

    def __repr__(cls):
        return "typing.TypeAliasType"

    def __instancecheck__(cls, instance):
        return type(instance).__name__ == "typing.TypeAliasType"


class TypeAliasType(metaclass=_TypeAliasTypeMeta):
    __slots__ = ("__name__", "__value__", "__type_params__")
    __module__ = "typing"

    def __new__(cls, name, value, *, type_params=()):
        self = super().__new__(cls)
        self.__name__ = name
        self.__value__ = value
        self.__type_params__ = tuple(type_params)
        return self

    def __repr__(self):
        return self.__name__


class _BaseTypeParameter:
    __slots__ = (
        "__name__",
        "__constraints__",
        "__bound__",
        "__default__",
        "__covariant__",
        "__contravariant__",
        "__infer_variance__",
    )
    __module__ = "typing"

    def __or__(self, other):
        return Union[self, other]

    def __ror__(self, other):
        return Union[other, self]

    def has_default(self):
        return self.__default__ is not NoDefault


class TypeVar(_BaseTypeParameter):
    __slots__ = ()
    __module__ = "typing"

    def __new__(cls, name, *constraints, bound=None, default=NoDefault, covariant=False, contravariant=False, infer_variance=False):
        if not isinstance(name, str):
            raise TypeError("TypeVar name must be a string")
        if covariant and contravariant:
            raise ValueError("Bivariant types are not supported.")
        if infer_variance and (covariant or contravariant):
            raise ValueError("Variance cannot be specified with infer_variance.")
        self = super().__new__(cls)
        self.__name__ = name
        self.__constraints__ = tuple(constraints)
        self.__bound__ = bound
        self.__default__ = default
        self.__covariant__ = bool(covariant)
        self.__contravariant__ = bool(contravariant)
        self.__infer_variance__ = bool(infer_variance)
        return self

    def __repr__(self):
        if self.__covariant__:
            return f"+{self.__name__}"
        if self.__contravariant__:
            return f"-{self.__name__}"
        return f"~{self.__name__}"

    def __typing_subst__(self, arg):
        import typing as _typing

        return _typing._typevar_subst(self, arg)


class ParamSpecArgs:
    __slots__ = ("__origin__",)
    __module__ = "typing"

    def __new__(cls, origin):
        self = super().__new__(cls)
        self.__origin__ = origin
        return self

    def __repr__(self):
        return f"{self.__origin__.__name__}.args"


class ParamSpecKwargs:
    __slots__ = ("__origin__",)
    __module__ = "typing"

    def __new__(cls, origin):
        self = super().__new__(cls)
        self.__origin__ = origin
        return self

    def __repr__(self):
        return f"{self.__origin__.__name__}.kwargs"


class ParamSpec(_BaseTypeParameter):
    __slots__ = ("args", "kwargs")
    __module__ = "typing"

    def __new__(cls, name, *, default=NoDefault):
        if not isinstance(name, str):
            raise TypeError("ParamSpec name must be a string")
        self = super().__new__(cls)
        self.__name__ = name
        self.__constraints__ = ()
        self.__bound__ = None
        self.__default__ = default
        self.__covariant__ = False
        self.__contravariant__ = False
        self.__infer_variance__ = False
        self.args = ParamSpecArgs(self)
        self.kwargs = ParamSpecKwargs(self)
        return self

    def __repr__(self):
        return f"~{self.__name__}"

    def __typing_subst__(self, arg):
        import typing as _typing

        return _typing._paramspec_subst(self, arg)

    def __typing_prepare_subst__(self, alias, args):
        import typing as _typing

        return _typing._paramspec_prepare_subst(self, alias, args)


class TypeVarTuple:
    __slots__ = ("__name__", "__default__")
    __module__ = "typing"

    def __new__(cls, name, *, default=NoDefault):
        if not isinstance(name, str):
            raise TypeError("TypeVarTuple name must be a string")
        self = super().__new__(cls)
        self.__name__ = name
        self.__default__ = default
        return self

    def __repr__(self):
        return self.__name__

    def has_default(self):
        return self.__default__ is not NoDefault

    def __typing_prepare_subst__(self, alias, args):
        import typing as _typing

        return _typing._typevartuple_prepare_subst(self, alias, args)


class _UnionProxy:
    __slots__ = ("__args__", "__parameters__")
    __module__ = "typing"

    def __new__(cls, args):
        self = super().__new__(cls)
        self.__args__ = tuple(args)
        try:
            import typing as _typing

            self.__parameters__ = _typing._collect_type_parameters(self.__args__)
        except Exception:
            self.__parameters__ = tuple(a for a in self.__args__ if hasattr(a, "__typing_subst__"))
        return self

    def __or__(self, other):
        return Union[self, other]

    def __ror__(self, other):
        return Union[other, self]

    def __repr__(self):
        try:
            import typing as _typing

            render = _typing._type_repr
        except Exception:
            render = repr
        inner = ", ".join(render(arg) for arg in self.__args__)
        return f"typing.Union[{inner}]"

    def __eq__(self, other):
        return isinstance(other, (_UnionProxy, _RUNTIME_UNION_TYPE)) and set(self.__args__) == set(other.__args__)

    def __hash__(self):
        return hash(frozenset(self.__args__))


try:
    _RUNTIME_UNION_TYPE = type(int | str)
except Exception:
    _RUNTIME_UNION_TYPE = ()


def _iter_union_args(value):
    if value is None:
        yield type(None)
        return
    if isinstance(value, _UnionProxy):
        yield from value.__args__
        return
    if _RUNTIME_UNION_TYPE and isinstance(value, _RUNTIME_UNION_TYPE):
        yield from value.__args__
        return
    yield value


class _UnionMeta(type):
    __module__ = "typing"

    def __repr__(cls):
        return "typing.Union"

    def __instancecheck__(cls, instance):
        return isinstance(instance, _UnionProxy) or (_RUNTIME_UNION_TYPE and isinstance(instance, _RUNTIME_UNION_TYPE))

    def __getitem__(cls, parameters):
        if not isinstance(parameters, tuple):
            parameters = (parameters,)
        flattened = []
        for parameter in parameters:
            for item in _iter_union_args(parameter):
                if item not in flattened:
                    flattened.append(item)
        if not flattened:
            raise TypeError("Cannot take a Union of no types.")
        return _UnionProxy(tuple(flattened))


class Union(metaclass=_UnionMeta):
    __slots__ = ()
    __module__ = "typing"


class Generic:
    __slots__ = ()
    __module__ = "typing"

    @classmethod
    def __class_getitem__(cls, args):
        import typing as _typing

        return _typing._generic_class_getitem(cls, args)

    def __init_subclass__(cls, *args, **kwargs):
        import typing as _typing

        return _typing._generic_init_subclass(cls, *args, **kwargs)
